1	/**
2	 * Fabricator — unit tests.
3	 *
4	 * Tests engine design registration from kits and apparatus supportKits,
5	 * and FabricatorApi.getEngineDesign() lookup. Uses a mock guild() singleton
6	 * to simulate the plugin environment.
7	 */
8	
9	import { describe, it, afterEach } from 'node:test';
10	import assert from 'node:assert/strict';
11	
12	import {
13	  setGuild,
14	  clearGuild,
15	} from '@shardworks/nexus-core';
16	import type {
17	  Guild,
18	  KitEntry,
19	  LoadedKit,
20	  LoadedApparatus,
21	  StartupContext,
22	} from '@shardworks/nexus-core';
23	
24	import {
25	  createFabricator,
26	  type FabricatorApi,
27	  type EngineDesign,
28	} from './fabricator.ts';
29	
30	// ── Test helpers ──────────────────────────────────────────────────────
31	
32	/** Create a minimal valid engine design for testing. */
33	function mockEngine(id: string): EngineDesign {
34	  return {
35	    id,
36	    async run(_givens, _ctx) {
37	      return { status: 'completed', yields: null };
38	    },
39	  };
40	}
41	
42	/** Build a mock LoadedKit with engine contributions. */
43	function mockKit(id: string, engines: Record<string, unknown>): LoadedKit {
44	  return {
45	    packageName: `@test/${id}`,
46	    id,
47	    version: '0.0.0',
48	    kit: { engines },
49	  };
50	}
51	
52	/** Build a mock LoadedApparatus with optional supportKit engines. */
53	function mockApparatus(
54	  id: string,
55	  supportKitEngines?: Record<string, unknown>,
56	): LoadedApparatus {
57	  return {
58	    packageName: `@test/${id}`,
59	    id,
60	    version: '0.0.0',
61	    apparatus: {
62	      start() {},
63	      ...(supportKitEngines ? { supportKit: { engines: supportKitEngines } } : {}),
64	    },
65	  };
66	}
67	
68	/** Wire a mock Guild into the singleton. */
69	function wireGuild(opts: {
70	  kits?: LoadedKit[];
71	  apparatuses?: LoadedApparatus[];
72	}): void {
73	  const kits = opts.kits ?? [];
74	  const apparatuses = opts.apparatuses ?? [];
75	
76	  const mockGuild: Guild = {
77	    home: '/tmp/test-guild',
78	    apparatus<T>(_name: string): T {
79	      throw new Error('Not implemented in test');
80	    },
81	    config<T>(_pluginId: string): T {
82	      return {} as T;
83	    },
84	    writeConfig() {},
85	    guildConfig() {
86	      return { name: 'test', nexus: '0.0.0', workshops: {}, plugins: [] };
87	    },
88	    kits() { return [...kits]; },
89	    apparatuses() { return [...apparatuses]; },
90	    startupWarnings() { return []; },
91	  };
92	
93	  setGuild(mockGuild);
94	}
95	
96	const FRAMEWORK_KIT_FIELDS = new Set(['requires', 'recommends']);
97	
98	function buildKitEntries(kits: LoadedKit[], apparatuses: LoadedApparatus[]): KitEntry[] {
99	  const entries: KitEntry[] = [];
100	  for (const kit of kits) {
101	    for (const [type, value] of Object.entries(kit.kit)) {
102	      if (FRAMEWORK_KIT_FIELDS.has(type)) continue;
103	      entries.push({ pluginId: kit.id, packageName: kit.packageName, type, value });
104	    }
105	  }
106	  for (const app of apparatuses) {
107	    const bag = app.apparatus.supportKit;
108	    if (!bag || typeof bag !== 'object') continue;
109	    for (const [type, value] of Object.entries(bag)) {
110	      if (FRAMEWORK_KIT_FIELDS.has(type)) continue;
111	      entries.push({ pluginId: app.id, packageName: app.packageName, type, value });
112	    }
113	  }
114	  return entries;
115	}
116	
117	/**
118	 * Build a StartupContext that captures event subscriptions.
119	 * Returns both the context and a fire() function to trigger events.
120	 */
121	function buildTestContext(kitEntries: KitEntry[] = []): {
122	  ctx: StartupContext;
123	  fire: (event: string, ...args: unknown[]) => Promise<void>;
124	} {
125	  const handlers = new Map<string, Array<(...args: unknown[]) => void | Promise<void>>>();
126	
127	  const ctx: StartupContext = {
128	    on(event, handler) {
129	      const list = handlers.get(event) ?? [];
130	      list.push(handler);
131	      handlers.set(event, list);
132	    },
133	    kits(type: string): KitEntry[] { return [...kitEntries.filter(e => e.type === type)]; },
134	  };
135	
136	  async function fire(event: string, ...args: unknown[]): Promise<void> {
137	    for (const h of handlers.get(event) ?? []) {
138	      await h(...args);
139	    }
140	  }
141	
142	  return { ctx, fire };
143	}
144	
145	/** Start the Fabricator and return its API. */
146	function startFabricator(opts: {
147	  kits?: LoadedKit[];
148	  apparatuses?: LoadedApparatus[];
149	}): { api: FabricatorApi } {
150	  wireGuild(opts);
151	  const kitEntries = buildKitEntries(opts.kits ?? [], opts.apparatuses ?? []);
152	
153	  const plugin = createFabricator();
154	  const api = ('apparatus' in plugin ? plugin.apparatus.provides : null) as FabricatorApi;
155	  assert.ok(api, 'Fabricator must expose provides');
156	
157	  const { ctx } = buildTestContext(kitEntries);
158	  if ('apparatus' in plugin) {
159	    plugin.apparatus.start(ctx);
160	  }
161	
162	  return { api };
163	}
164	
165	// ── Tests ─────────────────────────────────────────────────────────────
166	
167	describe('Fabricator', () => {
168	  afterEach(() => {
169	    clearGuild();
170	  });
171	
172	  describe('getEngineDesign()', () => {
173	    it('returns undefined for an unknown engine ID', () => {
174	      const { api } = startFabricator({});
175	      assert.equal(api.getEngineDesign('nonexistent'), undefined);
176	    });
177	
178	    it('finds an engine registered from a kit', () => {
179	      const engine = mockEngine('draft');
180	      const kit = mockKit('my-kit', { draft: engine });
181	      const { api } = startFabricator({ kits: [kit] });
182	
183	      const found = api.getEngineDesign('draft');
184	      assert.ok(found, 'engine should be found');
185	      assert.equal(found.id, 'draft');
186	      assert.equal(found, engine);
187	    });
188	
189	    it('registers engines from multiple kits', () => {
190	      const alpha = mockEngine('alpha');
191	      const beta = mockEngine('beta');
192	      const { api } = startFabricator({
193	        kits: [
194	          mockKit('kit-a', { alpha }),
195	          mockKit('kit-b', { beta }),
196	        ],
197	      });
198	
199	      assert.equal(api.getEngineDesign('alpha'), alpha);
200	      assert.equal(api.getEngineDesign('beta'), beta);
201	    });
202	
203	    it('throws when two kits contribute the same engine-design id (kit-vs-kit collision is fatal)', () => {
204	      const engine1 = mockEngine('draft');
205	      const engine2 = mockEngine('draft');
206	      assert.throws(
207	        () =>
208	          startFabricator({
209	            kits: [
210	              mockKit('kit-1', { draft: engine1 }),
211	              mockKit('kit-2', { draft: engine2 }),
212	            ],
213	          }),
214	        (err: Error) => {
215	          // Error must name both contributing plugins and the conflicting engine-design id.
216	          return (
217	            /engines/.test(err.message) &&
218	            /draft/.test(err.message) &&
219	            /kit-1/.test(err.message) &&
220	            /kit-2/.test(err.message)
221	          );
222	        },
223	        'kit-vs-kit engine-design collision must throw and name both plugins + the engine id',
224	      );
225	    });
226	
227	    it('registers engines from apparatus supportKit (via Wire phase)', () => {
228	      const engine = mockEngine('implement');
229	      const app = mockApparatus('my-apparatus', { implement: engine });
230	
231	      const { api } = startFabricator({ apparatuses: [app] });
232	
233	      const found = api.getEngineDesign('implement');
234	      assert.ok(found, 'engine should be found');
235	      assert.equal(found.id, 'implement');
236	      assert.equal(found, engine);
237	    });
238	
239	    it('skips entries missing the id field silently', () => {
240	      const kit = mockKit('messy-kit', {
241	        noId: { run: async () => ({ status: 'completed', yields: null }) },
242	      });
243	      // Should not throw
244	      const { api } = startFabricator({ kits: [kit] });
245	      assert.equal(api.getEngineDesign('noId'), undefined);
246	    });
247	
248	    it('skips entries missing the run field silently', () => {
249	      const kit = mockKit('messy-kit', {
250	        noRun: { id: 'draft' },
251	      });
252	      const { api } = startFabricator({ kits: [kit] });
253	      assert.equal(api.getEngineDesign('draft'), undefined);
254	    });
255	
256	    it('skips null and primitive entries silently, keeps valid ones', () => {
257	      const valid = mockEngine('valid');
258	      const kit = mockKit('messy-kit', {
259	        a: null,
260	        b: 'not-an-engine',
261	        c: 42,
262	        d: valid,
263	      });
264	      const { api } = startFabricator({ kits: [kit] });
265	
266	      assert.equal(api.getEngineDesign('valid'), valid);
267	      assert.equal(api.getEngineDesign('a'), undefined);
268	    });
269	
270	    it('ignores a kit with no engines field', () => {
271	      const kit: LoadedKit = {
272	        packageName: '@test/no-engines',
273	        id: 'no-engines',
274	        version: '0.0.0',
275	        kit: {},
276	      };
277	      // Should not throw
278	      const { api } = startFabricator({ kits: [kit] });
279	      assert.equal(api.getEngineDesign('anything'), undefined);
280	    });
281	
282	    it('ignores an apparatus with no supportKit', () => {
283	      const app = mockApparatus('bare-apparatus');
284	      // Should not throw
285	      const { api } = startFabricator({ apparatuses: [app] });
286	      assert.equal(api.getEngineDesign('anything'), undefined);
287	    });
288	
289	    it('ignores an apparatus supportKit with no engines field', () => {
290	      const app: LoadedApparatus = {
291	        packageName: '@test/bare',
292	        id: 'bare',
293	        version: '0.0.0',
294	        apparatus: {
295	          start() {},
296	          supportKit: {},
297	        },
298	      };
299	      // Should not throw
300	      const { api } = startFabricator({ apparatuses: [app] });
301	      assert.equal(api.getEngineDesign('anything'), undefined);
302	    });
303	
304	    it('handles engines from both kits and apparatus supportKits together', () => {
305	      const kitEngine = mockEngine('kit-engine');
306	      const apparatusEngine = mockEngine('apparatus-engine');
307	
308	      const { api } = startFabricator({
309	        kits: [mockKit('my-kit', { kitEngine })],
310	        apparatuses: [mockApparatus('my-apparatus', { apparatusEngine })],
311	      });
312	
313	      assert.equal(api.getEngineDesign('kit-engine'), kitEngine);
314	      assert.equal(api.getEngineDesign('apparatus-engine'), apparatusEngine);
315	    });
316	  });
317	
318	  describe('listEngineDesigns()', () => {
319	    it('returns empty array before registering anything', () => {
320	      const { api } = startFabricator({});
321	      const result = api.listEngineDesigns();
322	      assert.deepEqual(result, []);
323	    });
324	
325	    it('returns correct EngineDesignInfo for two designs from different plugins', () => {
326	      const engineA = mockEngine('alpha');
327	      const engineB = mockEngine('beta');
328	      const { api } = startFabricator({
329	        kits: [
330	          mockKit('plugin-a', { alpha: engineA }),
331	          mockKit('plugin-b', { beta: engineB }),
332	        ],
333	      });
334	
335	      const result = api.listEngineDesigns();
336	      assert.equal(result.length, 2);
337	
338	      const alpha = result.find((d) => d.id === 'alpha');
339	      assert.ok(alpha, 'alpha should be in list');
340	      assert.equal(alpha.pluginId, 'plugin-a');
341	      assert.equal(alpha.hasCollect, false);
342	
343	      const beta = result.find((d) => d.id === 'beta');
344	      assert.ok(beta, 'beta should be in list');
345	      assert.equal(beta.pluginId, 'plugin-b');
346	      assert.equal(beta.hasCollect, false);
347	    });
348	
349	    it('reports hasCollect: true for engine with collect method', () => {
350	      const engineWithCollect: EngineDesign = {
351	        id: 'quick-engine',
352	        async run() { return { status: 'completed', yields: null }; },
353	        async collect() { return { result: 'done' }; },
354	      };
355	      const engineWithoutCollect = mockEngine('plain-engine');
356	
357	      const { api } = startFabricator({
358	        kits: [
359	          mockKit('my-kit', { quick: engineWithCollect, plain: engineWithoutCollect }),
360	        ],
361	      });
362	
363	      const result = api.listEngineDesigns();
364	      const quick = result.find((d) => d.id === 'quick-engine');
365	      assert.ok(quick, 'quick-engine should be in list');
366	      assert.equal(quick.hasCollect, true);
367	
368	      const plain = result.find((d) => d.id === 'plain-engine');
369	      assert.ok(plain, 'plain-engine should be in list');
370	      assert.equal(plain.hasCollect, false);
371	    });
372	
373	    it('throws on duplicate engine-design id during startup (kit-vs-kit collision is fatal)', () => {
374	      // Sibling of the throw-on-collision test in getEngineDesign() — pinned
375	      // here to keep listEngineDesigns()'s contract aligned: duplicate ids
376	      // never reach the list because startup refuses to complete.
377	      const engine1 = mockEngine('shared');
378	      const engine2 = mockEngine('shared');
379	      assert.throws(
380	        () =>
381	          startFabricator({
382	            kits: [
383	              mockKit('plugin-1', { e: engine1 }),
384	              mockKit('plugin-2', { e: engine2 }),
385	            ],
386	          }),
387	        (err: Error) => {
388	          return (
389	            /engines/.test(err.message) &&
390	            /shared/.test(err.message) &&
391	            /plugin-1/.test(err.message) &&
392	            /plugin-2/.test(err.message)
393	          );
394	        },
395	        'duplicate engine-design id must throw at startup',
396	      );
397	    });
398	  });
399	});
